def detect_os():
    """
    Detect the operating system.
    Returns one of: 'cygwin', 'mac', 'linux', 'wsl', 'windows', 'bsd', or 'unknown'
    """
    import platform
    syst = platform.system().lower()
    osname = 'unknown'

    if 'cygwin' in syst:
        osname = 'cygwin'
    elif 'darwin' in syst:
        osname = 'mac'
    elif 'linux' in syst:
        osname = 'linux'
        # detect WSL https://github.com/Microsoft/BashOnWindows/issues/423
        try:
            with open('/proc/version', 'r') as f:
                if 'microsoft' in f.read().lower():
                    osname = 'wsl'
        except:
            pass
    elif 'windows' in syst:
        osname = 'windows'
    elif 'bsd' in syst:
        osname = 'bsd'

    return osname
